import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { useT } from '../context/LanguageContext';
import './Inscriptions.css';

export default function Inscriptions() {
  const { auth, apiHeaders } = useAuth();
  const t = useT();
  const [dias, setDias] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [expanded, setExpanded] = useState(null);

  useEffect(() => {
    if (!auth?.uuid) return;
    axios.get(`/api/student/dias/${auth.uuid}`, { headers: apiHeaders })
      .then(r => {
        const sorted = [...(r.data || [])].sort((a, b) => b.anneeAcademiqueId - a.anneeAcademiqueId);
        setDias(sorted);
        if (sorted.length > 0) setExpanded(sorted[0].id);
      })
      .catch(() => setError(t.inscriptions.errorLoad))
      .finally(() => setLoading(false));
  }, [auth, apiHeaders]); // eslint-disable-line

  if (loading) return <div className="page-loader"><div className="spinner" /></div>;
  if (error) return <div className="error-banner">{error}</div>;

  return (
    <div className="inscriptions-page">
      <div className="page-header">
        <div>
          <h1>{t.inscriptions.title}</h1>
          <p className="page-subtitle">{dias.length} {t.inscriptions.subtitle}</p>
        </div>
      </div>

      {dias.length === 0 ? (
        <div className="empty-state">
          <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>
          <p>{t.inscriptions.none}</p>
        </div>
      ) : (
        <div className="accordion">
          {dias.map((dia, idx) => (
            <div key={dia.id} className={`accordion-item ${expanded === dia.id ? 'open' : ''}`}>
              <button className="accordion-header" onClick={() => setExpanded(expanded === dia.id ? null : dia.id)}>
                <div className="acc-left">
                  <span className={`year-badge ${idx === 0 ? 'current' : ''}`}>
                    {idx === 0 ? '● ' : ''}{dia.anneeAcademiqueCode}
                  </span>
                  <div className="acc-meta">
                    <span className="acc-level">{dia.niveauLibelleLongLt}</span>
                    <span className="acc-filiere">{dia.ofLlFiliere}</span>
                  </div>
                </div>
                <span className="acc-chevron">{expanded === dia.id ? '▲' : '▼'}</span>
              </button>

              {expanded === dia.id && (
                <div className="accordion-body">
                  <div className="detail-grid">
                    <DetailItem label={t.inscriptions.numInscription} value={dia.numeroInscription} mono />
                    <DetailItem label={t.inscriptions.etablissement}  value={dia.llEtablissementLatin} />
                    <DetailItem label={t.inscriptions.niveau}         value={dia.niveauLibelleLongLt} />
                    <DetailItem label={t.inscriptions.cycle}          value={dia.refLibelleCycle} />
                    <DetailItem label={t.inscriptions.domaine}        value={dia.ofLlDomaine} />
                    <DetailItem label={t.inscriptions.filiere}        value={dia.ofLlFiliere} />
                    {dia.ofLlSpecialite && <DetailItem label={t.inscriptions.specialite} value={dia.ofLlSpecialite} />}
                    <DetailItem label={t.inscriptions.arabicEtab}     value={dia.llEtablissementArabe} arabic />
                    <DetailItem label={t.inscriptions.arabicFiliere}  value={dia.ofLlFiliereArabe} arabic />
                    {dia.ofLlSpecialiteArabe && <DetailItem label={t.inscriptions.arabicSpecialite} value={dia.ofLlSpecialiteArabe} arabic />}
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function DetailItem({ label, value, mono, arabic }) {
  if (!value) return null;
  return (
    <div className="detail-item">
      <span className="detail-label">{label}</span>
      <span className={`detail-value ${mono ? 'mono' : ''} ${arabic ? 'arabic' : ''}`}>{value}</span>
    </div>
  );
}
